function drawEnemyShot(e){if(e.type==='gear'){drawGear(e.x,e.y,e.r,e.spin,e.c,e.s);return}ctx.save();if(e.type==='steam'){ctx.globalAlpha=.42;ctx.fillStyle=e.c;ctx.beginPath();ctx.arc(e.x,e.y,e.r,0,Math.PI*2);ctx.arc(e.x+e.r*.42,e.y-e.r*.12,e.r*.72,0,Math.PI*2);ctx.arc(e.x-e.r*.35,e.y+e.r*.18,e.r*.62,0,Math.PI*2);ctx.fill();ctx.restore();return}if(e.type==='beam'){ctx.globalCompositeOperation='lighter';ctx.strokeStyle=e.c;ctx.lineWidth=5;ctx.beginPath();ctx.moveTo(e.x-e.vx*3,e.y-e.vy*3);ctx.lineTo(e.x+e.vx*5,e.y+e.vy*5);ctx.stroke()}else if(e.type==='volt'){ctx.strokeStyle=e.c;ctx.lineWidth=3;ctx.beginPath();ctx.moveTo(e.x-e.vx*4,e.y-e.vy*4);for(let i=0;i<4;i++)ctx.lineTo(e.x-e.vx*(3-i)+Math.sin(e.spin+i)*7,e.y-e.vy*(3-i)+Math.cos(e.spin+i)*7);ctx.stroke()}else if(e.type==='mine'){drawGear(e.x,e.y,e.r,e.spin,e.c,e.s);ctx.globalAlpha=.45;ctx.strokeStyle='#f8fafc';ctx.lineWidth=2;ctx.beginPath();ctx.arc(e.x,e.y,e.r*1.45+Math.sin(e.life*.18)*3,0,Math.PI*2);ctx.stroke();ctx.restore();return}else{ctx.fillStyle=e.c;ctx.beginPath();ctx.arc(e.x,e.y,e.r,0,Math.PI*2);ctx.fill();ctx.fillStyle='rgba(255,255,255,.55)';ctx.beginPath();ctx.arc(e.x-e.r*.28,e.y-e.r*.34,e.r*.34,0,Math.PI*2);ctx.fill()}ctx.restore()}
